export const DB_INIT_SCRIPTS: { name: string; sql: string }[] = [
  { name: "01_extensions_and_schema.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — ERP & FINANCIAL SYSTEM\n--  01 — Extensions, Schema, Roles, Enumerations\n--  -------------------------------------------------------------------------\n--  Legal issuer of all financial/legal documents: \"Ali Jafari\"\n--  Design principles:\n--    * Schema-per-tenant isolation  (tenant schema: arka)\n--    * Absolute financial precision  NUMERIC(78,0)  (amounts in minor units)\n--    * Zero hard-deletes  (soft delete via deleted_at + partial indexes)\n--    * Tamper-evident audit  (JSONB AFTER triggers + hash chaining)\n--  Target: PostgreSQL 16+\n-- =============================================================================\n\nSET client_min_messages = WARNING;\n\n-- ---------------------------------------------------------------------------\n--  Extensions (installed in a shared schema so every tenant can reference)\n-- ---------------------------------------------------------------------------\nCREATE EXTENSION IF NOT EXISTS pgcrypto;      -- gen_random_uuid(), digest(), hmac()\nCREATE EXTENSION IF NOT EXISTS pg_trgm;       -- trigram indexes for fuzzy search\nCREATE EXTENSION IF NOT EXISTS btree_gist;    -- exclusion constraints (asset booking)\nCREATE EXTENSION IF NOT EXISTS \"uuid-ossp\";   -- convenience uuid helpers\n\n-- ---------------------------------------------------------------------------\n--  Tenant schema\n-- ---------------------------------------------------------------------------\nCREATE SCHEMA IF NOT EXISTS arka;\n\n-- Least-privilege application role (used by the NestJS connection pool).\nDO $$\nBEGIN\n  IF NOT EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'arka_app') THEN\n    CREATE ROLE arka_app LOGIN PASSWORD 'bf6db4d6e7c9f551e1f3844a11e51b490a11befe1dae955c' NOSUPERUSER NOCREATEDB NOCREATEROLE;\n  END IF;\nEND$$;\n\nGRANT USAGE ON SCHEMA arka TO arka_app;\nALTER DEFAULT PRIVILEGES IN SCHEMA arka GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO arka_app;\nALTER DEFAULT PRIVILEGES IN SCHEMA arka GRANT USAGE, SELECT ON SEQUENCES TO arka_app;\n\nSET search_path TO arka, public;\n\n-- ---------------------------------------------------------------------------\n--  Enumerated types\n-- ---------------------------------------------------------------------------\nDO $$\nBEGIN\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'user_role') THEN\n    CREATE TYPE arka.user_role AS ENUM\n      ('CEO','ACCOUNTANT','SALES','DESIGNER','DEVELOPER','PHOTOGRAPHER','CUSTOMER','GUEST');\n  END IF;\n\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'account_type') THEN\n    CREATE TYPE arka.account_type AS ENUM\n      ('ASSET','LIABILITY','EQUITY','INCOME','EXPENSE');\n  END IF;\n\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'normal_balance') THEN\n    CREATE TYPE arka.normal_balance AS ENUM ('DEBIT','CREDIT');\n  END IF;\n\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'journal_status') THEN\n    CREATE TYPE arka.journal_status AS ENUM ('DRAFT','POSTED','REVERSED','VOID');\n  END IF;\n\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'audit_action') THEN\n    CREATE TYPE arka.audit_action AS ENUM ('INSERT','UPDATE','DELETE');\n  END IF;\n\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'project_status') THEN\n    CREATE TYPE arka.project_status AS ENUM\n      ('LEAD','PROPOSAL','CONTRACT','ACTIVE','ON_HOLD','DELIVERED','CLOSED','CANCELLED');\n  END IF;\n\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'customer_kind') THEN\n    CREATE TYPE arka.customer_kind AS ENUM ('INDIVIDUAL','COMPANY');\n  END IF;\n\n  IF NOT EXISTS (SELECT 1 FROM pg_type WHERE typname = 'fiscal_period_status') THEN\n    CREATE TYPE arka.fiscal_period_status AS ENUM ('OPEN','LOCKED','CLOSED');\n  END IF;\nEND$$;\n\n-- ---------------------------------------------------------------------------\n--  Reusable trigger: maintain updated_at\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_touch_updated_at()\nRETURNS trigger\nLANGUAGE plpgsql\nAS $$\nBEGIN\n  NEW.updated_at := now();\n  RETURN NEW;\nEND;\n$$;\n\n-- ---------------------------------------------------------------------------\n--  Reusable trigger: optimistic-lock version bump on UPDATE\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_bump_version()\nRETURNS trigger\nLANGUAGE plpgsql\nAS $$\nBEGIN\n  IF TG_OP = 'UPDATE' THEN\n    NEW.balance_version := COALESCE(OLD.balance_version, 0) + 1;\n  END IF" },
  { name: "02_audit_hashchain.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 02 — Tamper-evident Audit Trail (JSONB + Hash Chain)\n--  -------------------------------------------------------------------------\n--  * Generic AFTER trigger captures OLD/NEW as JSONB for every audited table.\n--  * Each row is chained: row_hash = sha256(prev_hash || canonical_payload).\n--  * A transaction-level advisory lock serialises hash computation so the\n--    chain is deterministic even under heavy concurrency.\n--  * Verify integrity anytime with arka.fn_verify_audit_chain().\n-- =============================================================================\nSET search_path TO arka, public;\n\nCREATE TABLE arka.audit_log (\n    id            BIGINT       GENERATED ALWAYS AS IDENTITY PRIMARY KEY,\n    table_name    TEXT         NOT NULL,\n    record_id     TEXT         NOT NULL,               -- pk of the affected row (text form)\n    action        arka.audit_action NOT NULL,\n    actor_id      UUID,                                -- app.current_user_id (may be NULL for system)\n    actor_role    TEXT,\n    client_ip     INET,\n    old_data      JSONB,\n    new_data      JSONB,\n    changed_cols  TEXT[],\n    tx_id         BIGINT       NOT NULL DEFAULT txid_current(),\n    changed_at    TIMESTAMPTZ  NOT NULL,\n    prev_hash     BYTEA        NOT NULL,\n    row_hash      BYTEA        NOT NULL\n);\n\nCREATE INDEX idx_audit_table_record ON arka.audit_log (table_name, record_id);\nCREATE INDEX idx_audit_actor        ON arka.audit_log (actor_id);\nCREATE INDEX idx_audit_changed_at   ON arka.audit_log (changed_at DESC);\nCREATE INDEX idx_audit_new_data_gin ON arka.audit_log USING GIN (new_data);\n\nCOMMENT ON TABLE arka.audit_log IS\n  'Append-only, hash-chained audit trail. Never UPDATE/DELETE rows here.';\n\n-- ---------------------------------------------------------------------------\n--  Session context helpers — the app sets these per request via SET LOCAL.\n--    SELECT set_config('app.current_user_id',   '<uuid>', true);\n--    SELECT set_config('app.current_user_role', 'ACCOUNTANT', true);\n--    SELECT set_config('app.client_ip',         '203.0.113.7', true);\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.current_actor_id()\nRETURNS uuid LANGUAGE sql STABLE AS $$\n  SELECT NULLIF(current_setting('app.current_user_id', true), '')::uuid;\n$$;\n\nCREATE OR REPLACE FUNCTION arka.current_actor_role()\nRETURNS text LANGUAGE sql STABLE AS $$\n  SELECT NULLIF(current_setting('app.current_user_role', true), '');\n$$;\n\nCREATE OR REPLACE FUNCTION arka.current_client_ip()\nRETURNS inet LANGUAGE sql STABLE AS $$\n  SELECT NULLIF(current_setting('app.client_ip', true), '')::inet;\n$$;\n\n-- ---------------------------------------------------------------------------\n--  Canonical payload builder — the single source of truth for hashing so the\n--  live trigger and the verifier can never drift apart.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_audit_payload(\n    p_table   TEXT,\n    p_action  arka.audit_action,\n    p_record  TEXT,\n    p_old     JSONB,\n    p_new     JSONB,\n    p_actor   UUID,\n    p_when    TIMESTAMPTZ\n) RETURNS BYTEA\nLANGUAGE sql IMMUTABLE AS $$\n  SELECT convert_to(\n      p_table || '|' || p_action::text || '|' || COALESCE(p_record, '') || '|' ||\n      COALESCE(p_old::text, '') || '|' || COALESCE(p_new::text, '') || '|' ||\n      COALESCE(p_actor::text, '') || '|' || p_when::text,\n  'UTF8');\n$$;\n\n-- ---------------------------------------------------------------------------\n--  Generic audit trigger with hash chaining.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_audit()\nRETURNS trigger\nLANGUAGE plpgsql\nAS $$\nDECLARE\n    v_old        JSONB;\n    v_new        JSONB;\n    v_record_id  TEXT;\n    v_changed    TEXT[];\n    v_prev_hash  BYTEA;\n    v_row_hash   BYTEA;\n    v_action     arka.audit_action;\n    v_when       TIMESTAMPTZ := clock_timestamp();\nBEGIN\n    -- Serialise hash-chain writes for the lifetime of the transaction.\n    PERFORM pg_advisory_xact_lock(hashtext('arka.audit_log.chain'));\n\n    IF TG_OP = 'INSERT' THEN\n        v_action := 'INSERT'; v_new := to_jsonb(NEW); v_old := NULL;\n        v_record_id := (v_new ->> 'id');\n    ELSIF TG_OP = 'UPDATE' THEN\n        v_action := 'UPDATE'; v_new := to_jsonb(NEW); v_old := to_jsonb(OLD);\n        v_record_id := (v_new ->> 'id');\n        SELECT array_agg(key)\n          INTO v_changed\n          FROM jsonb_each(v_new) n\n         WHERE n.value IS DISTINCT FROM (v_old -> n.key);\n    ELSE  -- DELETE (soft-delete UPDATE is the normal path; hard delete is guarded elsewhere)\n        v_action := 'DELETE'; v_old := to_jsonb(OLD); v_new := NULL;\n        v_record_id := (v_old ->> 'id');\n    END IF;\n\n    SELECT row_hash INTO v_prev_hash FROM arka.audit_log ORDER BY id DESC LIMIT 1;\n    IF v_prev_hash IS NULL THEN\n        v_prev_hash := digest('ARKA-AUDIT-GENESIS', 'sha256');\n    END IF;\n\n    v_row_hash := digest(\n        v_prev_hash ||\n        arka.fn_audit_payload(TG_TABLE_NAME, v_action, v_record_id,\n                              v_old, v_new, arka.current_actor_id(), v_when),\n        'sha256');\n\n    INSERT INTO arka.audit_log\n        (table_name, record_id, action, actor_id, actor_role, client_ip,\n         old_data, new_data, changed_cols, changed_at, prev_hash, row_hash)\n    VALUES\n        (TG_TABLE_NAME, v_record_id, v_action,\n         arka.current_actor_id(), arka.current_actor_role(), arka.current_client_ip(),\n         v_old, v_new, v_changed, v_when, v_prev_hash, v_row_hash);\n\n    RETURN NULL;  -- AFTER trigger\nEND;\n$$;\n\n-- ---------------------------------------------------------------------------\n--  Integrity verifier — returns the first broken link, or no rows if intact.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_verify_audit_chain()\nRETURNS TABLE(broken_at_id BIGINT, expected_hash BYTEA, stored_hash BYTEA)\nLANGUAGE plpgsql STABLE\nAS $$\nDECLARE\n    r       RECORD;\n    v_prev  BYTEA := digest('ARKA-AUDIT-GENESIS', 'sha256');\n    v_calc  BYTEA;\nBEGIN\n    FOR r IN SELECT * FROM arka.audit_log ORDER BY id ASC LOOP\n        v_calc := digest(\n            r.prev_hash ||\n            arka.fn_audit_payload(r.table_name, r.action, r.record_id,\n                                  r.old_data, r.new_data, r.actor_id, r.changed_at),\n            'sha256');\n\n        IF r.prev_hash IS DISTINCT FROM v_prev OR r.row_hash IS DISTINCT FROM v_calc THEN\n            broken_at_id := r.id; expected_hash := v_calc; stored_hash := r.row_hash;\n            RETURN NEXT;\n            RETURN;\n        END IF;\n        v_prev := r.row_hash;\n    END LOOP;\nEND;\n$$;\n\n-- Harden: block UPDATE/DELETE on the audit log entirely.\nCREATE OR REPLACE FUNCTION arka.fn_audit_immutable()\nRETURNS trigger LANGUAGE plpgsql AS $$\nBEGIN\n  RAISE EXCEPTION 'audit_log is append-only; % is not permitted', TG_OP;\nEND;$$;\n\nCREATE TRIGGER trg_audit_immutable\n  BEFORE UPDATE OR DELETE ON arka.audit_log\n  FOR EACH ROW EXECUTE FUNCTION arka.fn_audit_immutable();\n" },
  { name: "03_identity_and_crm.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 03 — Identity, RBAC, Sessions, CRM core\n--  -------------------------------------------------------------------------\n--  * Argon2id password hashes are produced by the app layer (node-argon2);\n--    the DB stores the encoded string only.\n--  * PII (IBAN / national id / PAN) is stored as app-layer envelope-encrypted\n--    bytea plus a non-sensitive *_last4 for display. The plaintext never lands\n--    in the DB.\n--  * Soft-delete everywhere via deleted_at + partial unique indexes.\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---------------------------------------------------------------------------\n--  USERS\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.users (\n    id                UUID          PRIMARY KEY DEFAULT gen_random_uuid(),\n    email             TEXT          NOT NULL,          -- case-insensitive via lower() index\n    full_name         TEXT          NOT NULL,\n    role              arka.user_role NOT NULL DEFAULT 'GUEST',\n    password_hash     TEXT          NOT NULL,          -- argon2id encoded string\n    -- Step-up MFA (TOTP). Secret is envelope-encrypted by the app.\n    mfa_enabled       BOOLEAN       NOT NULL DEFAULT false,\n    mfa_secret_enc    BYTEA,\n    mfa_recovery_enc  BYTEA,\n    -- Security / lifecycle\n    is_active         BOOLEAN       NOT NULL DEFAULT true,\n    failed_logins     INTEGER       NOT NULL DEFAULT 0,\n    locked_until      TIMESTAMPTZ,\n    last_login_at     TIMESTAMPTZ,\n    password_changed_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n    balance_version   INTEGER       NOT NULL DEFAULT 0,   -- optimistic lock\n    metadata          JSONB         NOT NULL DEFAULT '{}'::jsonb,\n    created_at        TIMESTAMPTZ   NOT NULL DEFAULT now(),\n    updated_at        TIMESTAMPTZ   NOT NULL DEFAULT now(),\n    deleted_at        TIMESTAMPTZ,\n    CONSTRAINT chk_users_email CHECK (email ~* '^[^@\\s]+@[^@\\s]+\\.[^@\\s]+$')\n);\n\n-- One active account per email (soft-deleted rows may repeat).\nCREATE UNIQUE INDEX uq_users_email_active\n    ON arka.users (lower(email)) WHERE deleted_at IS NULL;\nCREATE INDEX idx_users_role   ON arka.users (role)  WHERE deleted_at IS NULL;\nCREATE INDEX idx_users_active ON arka.users (is_active) WHERE deleted_at IS NULL;\n\nCREATE TRIGGER trg_users_touch  BEFORE UPDATE ON arka.users\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_touch_updated_at();\nCREATE TRIGGER trg_users_version BEFORE UPDATE ON arka.users\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_bump_version();\nCREATE TRIGGER trg_users_audit  AFTER INSERT OR UPDATE OR DELETE ON arka.users\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_audit();\n\n-- ---------------------------------------------------------------------------\n--  RBAC — permissions catalogue + role grants + Segregation of Duties\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.permissions (\n    code        TEXT PRIMARY KEY,               -- e.g. 'ledger.post', 'fund.transfer'\n    description TEXT NOT NULL,\n    category    TEXT NOT NULL\n);\n\nCREATE TABLE arka.role_permissions (\n    role        arka.user_role NOT NULL,\n    permission  TEXT NOT NULL REFERENCES arka.permissions(code) ON DELETE CASCADE,\n    PRIMARY KEY (role, permission)\n);\n\n-- Segregation of Duties: pairs of permissions that must never coexist for one role.\nCREATE TABLE arka.sod_conflicts (\n    permission_a TEXT NOT NULL REFERENCES arka.permissions(code) ON DELETE CASCADE,\n    permission_b TEXT NOT NULL REFERENCES arka.permissions(code) ON DELETE CASCADE,\n    reason       TEXT NOT NULL,\n    PRIMARY KEY (permission_a, permission_b),\n    CONSTRAINT chk_sod_distinct CHECK (permission_a < permission_b)\n);\n\n-- Enforce SoD at write time: reject a grant that violates any conflict rule.\nCREATE OR REPLACE FUNCTION arka.fn_enforce_sod()\nRETURNS trigger LANGUAGE plpgsql AS $$\nDECLARE v_conflict RECORD;\nBEGIN\n    SELECT c.* INTO v_conflict\n    FROM arka.sod_conflicts c\n    JOIN arka.role_permissions rp ON rp.role = NEW.role\n     AND rp.permission = CASE WHEN c.permission_a = NEW.permission THEN c.permission_b\n                              ELSE c.permission_a END\n    WHERE NEW.permission IN (c.permission_a, c.permission_b)\n    LIMIT 1;\n\n    IF FOUND THEN\n        RAISE EXCEPTION 'SoD violation for role %: % conflicts with an existing grant (%)',\n            NEW.role, NEW.permission, v_conflict.reason;\n    END IF;\n    RETURN NEW;\nEND;$$;\n\nCREATE TRIGGER trg_role_perm_sod BEFORE INSERT OR UPDATE ON arka.role_permissions\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_enforce_sod();\n\n-- ---------------------------------------------------------------------------\n--  REFRESH TOKENS — rotation + reuse detection (only a SHA-256 hash is stored)\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.refresh_tokens (\n    id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),\n    user_id       UUID        NOT NULL REFERENCES arka.users(id) ON DELETE CASCADE,\n    token_hash    BYTEA       NOT NULL,                 -- sha256(raw token)\n    family_id     UUID        NOT NULL,                 -- rotation lineage\n    user_agent    TEXT,\n    client_ip     INET,\n    issued_at     TIMESTAMPTZ NOT NULL DEFAULT now(),\n    expires_at    TIMESTAMPTZ NOT NULL,\n    revoked_at    TIMESTAMPTZ,\n    replaced_by   UUID REFERENCES arka.refresh_tokens(id)\n);\nCREATE UNIQUE INDEX uq_refresh_token_hash ON arka.refresh_tokens (token_hash);\nCREATE INDEX idx_refresh_user   ON arka.refresh_tokens (user_id) WHERE revoked_at IS NULL;\nCREATE INDEX idx_refresh_family ON arka.refresh_tokens (family_id);\n\n-- ---------------------------------------------------------------------------\n--  CUSTOMERS (CRM anchor)\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.customers (\n    id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),\n    code          TEXT        NOT NULL,\n    kind          arka.customer_kind NOT NULL DEFAULT 'COMPANY',\n    display_name  TEXT        NOT NULL,\n    legal_name    TEXT,\n    tax_id_enc    BYTEA,                     -- envelope-encrypted national/tax id\n    tax_id_last4  TEXT,\n    iban_enc      BYTEA,                     -- envelope-encrypted IBAN\n    iban_last4    TEXT,\n    email         TEXT,\n    phone         TEXT,\n    address       TEXT,\n    -- Financial linkage: every customer maps to an AR sub-ledger account.\n    ar_account_id UUID,                      -- FK added after accounts table exists\n    credit_limit  NUMERIC(78,0) NOT NULL DEFAULT 0 CHECK (credit_limit >= 0),\n    notes         TEXT,\n    metadata      JSONB       NOT NULL DEFAULT '{}'::jsonb,\n    created_by    UUID REFERENCES arka.users(id),\n    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),\n    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now(),\n    deleted_at    TIMESTAMPTZ\n);\nCREATE UNIQUE INDEX uq_customers_code ON arka.customers (code) WHERE deleted_at IS NULL;\nCREATE INDEX idx_customers_name_trgm ON arka.customers USING GIN (display_name gin_trgm_ops);\n\nCREATE TRIGGER trg_customers_touch BEFORE UPDATE ON arka.customers\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_touch_updated_at();\nCREATE TRIGGER trg_customers_audit AFTER INSERT OR UPDATE OR DELETE ON arka.customers\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_audit();\n\n-- ---------------------------------------------------------------------------\n--  CRM PIPELINE — lead-to-cash stages captured as interactions\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.crm_interactions (\n    id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),\n    customer_id  UUID        NOT NULL REFERENCES arka.customers(id) ON DELETE CASCADE,\n    stage        TEXT        NOT NULL,   -- CALL | MEETING | PROPOSAL | CONTRACT | FOLLOWUP\n    subject      TEXT        NOT NULL,\n    body         TEXT,\n    owner_id     UUID REFERENCES arka.users(id),\n    occurred_at  TIMESTAMPTZ NOT NULL DEFAULT now(),\n    next_action_at TIMESTAMPTZ,\n    metadata     JSONB       NOT NULL DEFAULT '{}'::jsonb,\n    created_at   TIMESTAMPTZ NOT NULL DEFAULT now(),\n    deleted_at   TIMESTAMPTZ\n);\nCREATE INDEX idx_crm_customer ON arka.crm_interactions (customer_id, occurred_at DESC);\n" },
  { name: "04_accounting_core.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 04 — Double-Entry Accounting Core\n--  -------------------------------------------------------------------------\n--  Invariants enforced *in the database*:\n--    (I1) Every posted journal entry: SUM(debit) = SUM(credit)  (deferred CT).\n--    (I2) A line is either a debit or a credit, never both, never negative.\n--    (I3) Journal lines may only reference postable (leaf) active accounts.\n--    (I4) Posting locks account rows in deterministic id order (deadlock-free)\n--         and mutates cached balances atomically  (SELECT ... FOR UPDATE).\n--    (I5) Posting is rejected outside an OPEN fiscal period.\n--  Amounts are NUMERIC(78,0) integers in the smallest currency unit (Rial).\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---------------------------------------------------------------------------\n--  FISCAL PERIODS\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.fiscal_periods (\n    id          UUID        PRIMARY KEY DEFAULT gen_random_uuid(),\n    year_code   TEXT        NOT NULL,                  -- e.g. '1404'\n    period_no   SMALLINT    NOT NULL CHECK (period_no BETWEEN 1 AND 12),\n    starts_on   DATE        NOT NULL,\n    ends_on     DATE        NOT NULL,\n    status      arka.fiscal_period_status NOT NULL DEFAULT 'OPEN',\n    closed_at   TIMESTAMPTZ,\n    closed_by   UUID REFERENCES arka.users(id),\n    CONSTRAINT chk_period_range CHECK (ends_on >= starts_on),\n    CONSTRAINT uq_period UNIQUE (year_code, period_no),\n    -- No two periods may overlap (btree_gist).\n    CONSTRAINT excl_period_overlap\n        EXCLUDE USING gist (daterange(starts_on, ends_on, '[]') WITH &&)\n);\nCREATE INDEX idx_period_status ON arka.fiscal_periods (status);\n\nCREATE OR REPLACE FUNCTION arka.fn_period_for_date(p_date DATE)\nRETURNS arka.fiscal_periods LANGUAGE sql STABLE AS $$\n  SELECT * FROM arka.fiscal_periods\n   WHERE p_date BETWEEN starts_on AND ends_on\n   LIMIT 1;\n$$;\n\n-- ---------------------------------------------------------------------------\n--  CHART OF ACCOUNTS  (self-referencing hierarchy)\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.accounts (\n    id              UUID          PRIMARY KEY DEFAULT gen_random_uuid(),\n    code            TEXT          NOT NULL,\n    name            TEXT          NOT NULL,\n    account_type    arka.account_type   NOT NULL,\n    normal_balance  arka.normal_balance NOT NULL,\n    parent_id       UUID          REFERENCES arka.accounts(id),\n    is_postable     BOOLEAN       NOT NULL DEFAULT true,   -- only leaves are postable\n    is_active       BOOLEAN       NOT NULL DEFAULT true,\n    currency        CHAR(3)       NOT NULL DEFAULT 'IRR',\n    -- Cached natural balance (positive on the account's normal side).\n    balance         NUMERIC(78,0) NOT NULL DEFAULT 0,\n    balance_version INTEGER       NOT NULL DEFAULT 0,      -- optimistic lock\n    description     TEXT,\n    metadata        JSONB         NOT NULL DEFAULT '{}'::jsonb,\n    created_at      TIMESTAMPTZ   NOT NULL DEFAULT now(),\n    updated_at      TIMESTAMPTZ   NOT NULL DEFAULT now(),\n    deleted_at      TIMESTAMPTZ,\n    CONSTRAINT chk_account_not_self_parent CHECK (parent_id IS NULL OR parent_id <> id)\n);\nCREATE UNIQUE INDEX uq_accounts_code ON arka.accounts (code) WHERE deleted_at IS NULL;\nCREATE INDEX idx_accounts_parent ON arka.accounts (parent_id);\nCREATE INDEX idx_accounts_type   ON arka.accounts (account_type) WHERE deleted_at IS NULL;\n\nCREATE TRIGGER trg_accounts_touch   BEFORE UPDATE ON arka.accounts\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_touch_updated_at();\nCREATE TRIGGER trg_accounts_audit   AFTER INSERT OR UPDATE OR DELETE ON arka.accounts\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_audit();\n\n-- A parent account must not remain postable once it has children.\nCREATE OR REPLACE FUNCTION arka.fn_parent_not_postable()\nRETURNS trigger LANGUAGE plpgsql AS $$\nBEGIN\n    IF NEW.parent_id IS NOT NULL THEN\n        UPDATE arka.accounts SET is_postable = false\n         WHERE id = NEW.parent_id AND is_postable = true;\n    END IF;\n    RETURN NEW;\nEND;$$;\nCREATE TRIGGER trg_accounts_parent_leaf AFTER INSERT OR UPDATE OF parent_id ON arka.accounts\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_parent_not_postable();\n\n-- Now that accounts exist, wire the customer AR sub-ledger FK.\nALTER TABLE arka.customers\n    ADD CONSTRAINT fk_customers_ar_account\n    FOREIGN KEY (ar_account_id) REFERENCES arka.accounts(id);\n\n-- ---------------------------------------------------------------------------\n--  PROJECTS  (financial + delivery anchor)\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.projects (\n    id            UUID        PRIMARY KEY DEFAULT gen_random_uuid(),\n    code          TEXT        NOT NULL,\n    name          TEXT        NOT NULL,\n    customer_id   UUID        REFERENCES arka.customers(id),\n    manager_id    UUID        REFERENCES arka.users(id),\n    status        arka.project_status NOT NULL DEFAULT 'LEAD',\n    budget        NUMERIC(78,0) NOT NULL DEFAULT 0 CHECK (budget >= 0),\n    contract_value NUMERIC(78,0) NOT NULL DEFAULT 0 CHECK (contract_value >= 0),\n    cost_to_date  NUMERIC(78,0) NOT NULL DEFAULT 0 CHECK (cost_to_date >= 0),\n    progress_pct  NUMERIC(5,2)  NOT NULL DEFAULT 0 CHECK (progress_pct BETWEEN 0 AND 100),\n    starts_on     DATE,\n    due_on        DATE,\n    delivered_on  DATE,\n    description   TEXT,\n    metadata      JSONB       NOT NULL DEFAULT '{}'::jsonb,\n    created_by    UUID REFERENCES arka.users(id),\n    created_at    TIMESTAMPTZ NOT NULL DEFAULT now(),\n    updated_at    TIMESTAMPTZ NOT NULL DEFAULT now(),\n    deleted_at    TIMESTAMPTZ,\n    CONSTRAINT chk_project_dates CHECK (due_on IS NULL OR starts_on IS NULL OR due_on >= starts_on)\n);\nCREATE UNIQUE INDEX uq_projects_code ON arka.projects (code) WHERE deleted_at IS NULL;\nCREATE INDEX idx_projects_customer ON arka.projects (customer_id);\nCREATE INDEX idx_projects_status   ON arka.projects (status) WHERE deleted_at IS NULL;\nCREATE INDEX idx_projects_manager  ON arka.projects (manager_id);\n\nCREATE TRIGGER trg_projects_touch BEFORE UPDATE ON arka.projects\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_touch_updated_at();\nCREATE TRIGGER trg_projects_audit AFTER INSERT OR UPDATE OR DELETE ON arka.projects\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_audit();\n\n-- ---------------------------------------------------------------------------\n--  JOURNAL ENTRIES (header)\n-- ---------------------------------------------------------------------------\nCREATE SEQUENCE arka.seq_journal_no START 1000;\n\nCREATE TABLE arka.journal_entries (\n    id                UUID        PRIMARY KEY DEFAULT gen_random_uuid(),\n    entry_no          BIGINT      NOT NULL DEFAULT nextval('arka.seq_journal_no'),\n    entry_date        DATE        NOT NULL DEFAULT current_date,\n    memo              TEXT        NOT NULL,\n    reference         TEXT,                              -- external doc no / invoice no\n    source            TEXT        NOT NULL DEFAULT 'MANUAL',  -- MANUAL|INVOICE|PAYROLL|DEPRECIATION|FX\n    status            arka.journal_status NOT NULL DEFAULT 'DRAFT',\n    fiscal_period_id  UUID        REFERENCES arka.fiscal_periods(id),\n    project_id        UUID        REFERENCES arka.projects(id),\n    customer_id       UUID        REFERENCES arka.customers(id),\n    reversed_entry_id UUID        REFERENCES arka.journal_entries(id),  -- set on the reversing entry\n    posted_at         TIMESTAMPTZ,\n    posted_by         UUID        REFERENCES arka.users(id),\n    created_by        UUID        REFERENCES arka.users(id),\n    created_at        TIMESTAMPTZ NOT NULL DEFAULT now(),\n    updated_at        TIMESTAMPTZ NOT NULL DEFAULT now(),\n    deleted_at        TIMESTAMPTZ\n);\nCREATE UNIQUE INDEX uq_journal_entry_no ON arka.journal_entries (entry_no);\nCREATE INDEX idx_journal_date    ON arka.journal_entries (entry_date);\nCREATE INDEX idx_journal_status  ON arka.journal_entries (status);\nCREATE INDEX idx_journal_project ON arka.journal_entries (project_id);\nCREATE INDEX idx_journal_period  ON arka.journal_entries (fiscal_period_id);\n\nCREATE TRIGGER trg_journal_touch BEFORE UPDATE ON arka.journal_entries\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_touch_updated_at();\nCREATE TRIGGER trg_journal_audit AFTER INSERT OR UPDATE OR DELETE ON arka.journal_entries\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_audit();\n\n-- ---------------------------------------------------------------------------\n--  JOURNAL LINES (detail)\n-- ---------------------------------------------------------------------------\nCREATE TABLE arka.journal_lines (\n    id          UUID          PRIMARY KEY DEFAULT gen_random_uuid(),\n    entry_id    UUID          NOT NULL REFERENCES arka.journal_entries(id) ON DELETE CASCADE,\n    line_no     SMALLINT      NOT NULL,\n    account_id  UUID          NOT NULL REFERENCES arka.accounts(id),\n    debit       NUMERIC(78,0) NOT NULL DEFAULT 0 CHECK (debit  >= 0),\n    credit      NUMERIC(78,0) NOT NULL DEFAULT 0 CHECK (credit >= 0),\n    memo        TEXT,\n    project_id  UUID REFERENCES arka.projects(id),\n    metadata    JSONB         NOT NULL DEFAULT '{}'::jsonb,\n    -- (I2) exactly one side non-zero\n    CONSTRAINT chk_line_one_side CHECK (\n        (debit > 0 AND credit = 0) OR (credit > 0 AND debit = 0)\n    ),\n    CONSTRAINT uq_line_no UNIQUE (entry_id, line_no)\n);\nCREATE INDEX idx_lines_entry   ON arka.journal_lines (entry_id);\nCREATE INDEX idx_lines_account ON arka.journal_lines (account_id);\nCREATE INDEX idx_lines_project ON arka.journal_lines (project_id);\n\n-- (I3) postable + active account guard\nCREATE OR REPLACE FUNCTION arka.fn_line_account_guard()\nRETURNS trigger LANGUAGE plpgsql AS $$\nDECLARE v_acc arka.accounts;\nBEGIN\n    SELECT * INTO v_acc FROM arka.accounts WHERE id = NEW.account_id;\n    IF NOT FOUND THEN\n        RAISE EXCEPTION 'account % does not exist', NEW.account_id;\n    END IF;\n    IF v_acc.deleted_at IS NOT NULL OR NOT v_acc.is_active THEN\n        RAISE EXCEPTION 'account % (%) is inactive/deleted', v_acc.code, v_acc.name;\n    END IF;\n    IF NOT v_acc.is_postable THEN\n        RAISE EXCEPTION 'account % (%) is a control account and is not postable', v_acc.code, v_acc.name;\n    END IF;\n    RETURN NEW;\nEND;$$;\nCREATE TRIGGER trg_line_account_guard BEFORE INSERT OR UPDATE ON arka.journal_lines\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_line_account_guard();\n\n-- (I1) deferred balance check — only enforced for POSTED entries.\nCREATE OR REPLACE FUNCTION arka.fn_check_entry_balanced()\nRETURNS trigger LANGUAGE plpgsql AS $$\nDECLARE\n    v_entry_id UUID;\n    v_status   arka.journal_status;\n    v_debit    NUMERIC(78,0);\n    v_credit   NUMERIC(78,0);\n    v_lines    INTEGER;\nBEGIN\n    v_entry_id := COALESCE(NEW.entry_id, OLD.entry_id);\n\n    SELECT status INTO v_status FROM arka.journal_entries WHERE id = v_entry_id;\n    IF v_status IS NULL OR v_status <> 'POSTED' THEN\n        RETURN NULL;               -- drafts may be unbalanced\n    END IF;\n\n    SELECT COALESCE(SUM(debit),0), COALESCE(SUM(credit),0), COUNT(*)\n      INTO v_debit, v_credit, v_lines\n      FROM arka.journal_lines WHERE entry_id = v_entry_id;\n\n    IF v_lines < 2 THEN\n        RAISE EXCEPTION 'journal entry % must contain at least two lines', v_entry_id;\n    END IF;\n    IF v_debit <> v_credit THEN\n        RAISE EXCEPTION 'journal entry % is unbalanced: debit=% credit=%',\n            v_entry_id, v_debit, v_credit;\n    END IF;\n    RETURN NULL;\nEND;$$;\n\nCREATE CONSTRAINT TRIGGER trg_lines_balanced\n    AFTER INSERT OR UPDATE OR DELETE ON arka.journal_lines\n    DEFERRABLE INITIALLY DEFERRED\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_check_entry_balanced();\n\n-- Also re-check when a header flips to POSTED.\nCREATE OR REPLACE FUNCTION arka.fn_check_header_balanced()\nRETURNS trigger LANGUAGE plpgsql AS $$\nDECLARE v_debit NUMERIC(78,0); v_credit NUMERIC(78,0); v_lines INTEGER;\nBEGIN\n    IF NEW.status <> 'POSTED' THEN RETURN NULL; END IF;\n    SELECT COALESCE(SUM(debit),0), COALESCE(SUM(credit),0), COUNT(*)\n      INTO v_debit, v_credit, v_lines\n      FROM arka.journal_lines WHERE entry_id = NEW.id;\n    IF v_lines < 2 OR v_debit <> v_credit THEN\n        RAISE EXCEPTION 'entry % cannot be POSTED: lines=% debit=% credit=%',\n            NEW.id, v_lines, v_debit, v_credit;\n    END IF;\n    RETURN NULL;\nEND;$$;\nCREATE CONSTRAINT TRIGGER trg_header_balanced\n    AFTER UPDATE OF status ON arka.journal_entries\n    DEFERRABLE INITIALLY DEFERRED\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_check_header_balanced();\n" },
  { name: "05_posting_functions.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 05 — Posting Engine, Reversal, Fiscal Close\n--  -------------------------------------------------------------------------\n--  All balance mutations funnel through these SECURITY DEFINER functions so\n--  the invariants can never be bypassed by ad-hoc SQL from the app pool.\n--    * fn_post_journal_entry   — validates + locks accounts in id order + posts\n--    * fn_reverse_journal_entry — books a mirror entry, marks original REVERSED\n--    * fn_recompute_account_balance — self-healing recompute from posted lines\n--    * fn_close_fiscal_period  — advisory-locked year/period close to Retained\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---------------------------------------------------------------------------\n--  POST — the single mutating gate for the ledger.\n--  Deadlock avoidance: every concurrent poster acquires account row locks in\n--  ascending id order, so no two transactions can build a lock cycle.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_post_journal_entry(\n    p_entry_id UUID,\n    p_actor    UUID DEFAULT NULL\n) RETURNS arka.journal_entries\nLANGUAGE plpgsql\nSECURITY DEFINER\nSET search_path = arka, public\nAS $$\nDECLARE\n    v_entry   arka.journal_entries;\n    v_period  arka.fiscal_periods;\n    v_debit   NUMERIC(78,0);\n    v_credit  NUMERIC(78,0);\n    v_lines   INTEGER;\nBEGIN\n    -- 1) Serialise on the header row.\n    SELECT * INTO v_entry FROM arka.journal_entries\n      WHERE id = p_entry_id AND deleted_at IS NULL\n      FOR UPDATE;\n    IF NOT FOUND THEN\n        RAISE EXCEPTION 'journal entry % not found', p_entry_id USING ERRCODE = 'no_data_found';\n    END IF;\n    IF v_entry.status <> 'DRAFT' THEN\n        RAISE EXCEPTION 'journal entry % is % and cannot be posted', v_entry.entry_no, v_entry.status\n            USING ERRCODE = 'invalid_parameter_value';\n    END IF;\n\n    -- 2) Fiscal period must exist and be OPEN.\n    v_period := arka.fn_period_for_date(v_entry.entry_date);\n    IF v_period.id IS NULL THEN\n        RAISE EXCEPTION 'no fiscal period defined for date %', v_entry.entry_date;\n    END IF;\n    IF v_period.status <> 'OPEN' THEN\n        RAISE EXCEPTION 'fiscal period %/% is % — posting rejected',\n            v_period.year_code, v_period.period_no, v_period.status;\n    END IF;\n\n    -- 3) Balance validation.\n    SELECT COALESCE(SUM(debit),0), COALESCE(SUM(credit),0), COUNT(*)\n      INTO v_debit, v_credit, v_lines\n      FROM arka.journal_lines WHERE entry_id = p_entry_id;\n    IF v_lines < 2 THEN\n        RAISE EXCEPTION 'entry % must have >= 2 lines', v_entry.entry_no;\n    END IF;\n    IF v_debit <> v_credit THEN\n        RAISE EXCEPTION 'entry % unbalanced: debit=% credit=%', v_entry.entry_no, v_debit, v_credit;\n    END IF;\n\n    -- 4) Lock every involved account row in deterministic (ascending id) order.\n    PERFORM 1 FROM arka.accounts\n      WHERE id IN (SELECT DISTINCT account_id FROM arka.journal_lines WHERE entry_id = p_entry_id)\n      ORDER BY id\n      FOR UPDATE;\n\n    -- 5) Atomically fold the deltas into cached balances.\n    UPDATE arka.accounts a\n       SET balance = a.balance + agg.delta,\n           balance_version = a.balance_version + 1,\n           updated_at = now()\n      FROM (\n            SELECT jl.account_id,\n                   SUM(CASE WHEN acc.normal_balance = 'DEBIT'\n                            THEN jl.debit - jl.credit\n                            ELSE jl.credit - jl.debit END) AS delta\n              FROM arka.journal_lines jl\n              JOIN arka.accounts acc ON acc.id = jl.account_id\n             WHERE jl.entry_id = p_entry_id\n             GROUP BY jl.account_id\n           ) agg\n     WHERE a.id = agg.account_id;\n\n    -- 6) Flip the header to POSTED (fires the deferred header balance CT as backstop).\n    UPDATE arka.journal_entries\n       SET status = 'POSTED',\n           posted_at = now(),\n           posted_by = COALESCE(p_actor, arka.current_actor_id()),\n           fiscal_period_id = v_period.id\n     WHERE id = p_entry_id\n    RETURNING * INTO v_entry;\n\n    RETURN v_entry;\nEND;\n$$;\n\n-- ---------------------------------------------------------------------------\n--  REVERSE — books the exact mirror of a posted entry and marks it REVERSED.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_reverse_journal_entry(\n    p_entry_id UUID,\n    p_actor    UUID DEFAULT NULL,\n    p_date     DATE DEFAULT NULL,\n    p_memo     TEXT DEFAULT NULL\n) RETURNS arka.journal_entries\nLANGUAGE plpgsql\nSECURITY DEFINER\nSET search_path = arka, public\nAS $$\nDECLARE\n    v_src      arka.journal_entries;\n    v_new_id   UUID;\n    v_result   arka.journal_entries;\n    v_date     DATE;\nBEGIN\n    SELECT * INTO v_src FROM arka.journal_entries\n      WHERE id = p_entry_id AND deleted_at IS NULL FOR UPDATE;\n    IF NOT FOUND THEN\n        RAISE EXCEPTION 'journal entry % not found', p_entry_id;\n    END IF;\n    IF v_src.status <> 'POSTED' THEN\n        RAISE EXCEPTION 'only POSTED entries can be reversed (entry % is %)',\n            v_src.entry_no, v_src.status;\n    END IF;\n\n    v_date := COALESCE(p_date, current_date);\n\n    INSERT INTO arka.journal_entries\n        (memo, entry_date, reference, source, status, project_id, customer_id,\n         reversed_entry_id, created_by)\n    VALUES\n        (COALESCE(p_memo, 'Reversal of #' || v_src.entry_no || ' — ' || v_src.memo),\n         v_date, v_src.reference, 'REVERSAL', 'DRAFT', v_src.project_id, v_src.customer_id,\n         v_src.id, COALESCE(p_actor, arka.current_actor_id()))\n    RETURNING id INTO v_new_id;\n\n    -- Mirror the lines (swap debit <-> credit).\n    INSERT INTO arka.journal_lines (entry_id, line_no, account_id, debit, credit, memo, project_id)\n    SELECT v_new_id, line_no, account_id, credit, debit,\n           'Reversal: ' || COALESCE(memo, ''), project_id\n      FROM arka.journal_lines WHERE entry_id = p_entry_id;\n\n    -- Post the reversal (locks + balances applied through the standard gate).\n    v_result := arka.fn_post_journal_entry(v_new_id, p_actor);\n\n    -- Mark the source as REVERSED.\n    UPDATE arka.journal_entries SET status = 'REVERSED' WHERE id = p_entry_id;\n\n    RETURN v_result;\nEND;\n$$;\n\n-- ---------------------------------------------------------------------------\n--  SELF-HEAL — recompute a single account's cached balance from posted lines.\n--  Used by an integrity job; also handy after restores.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_recompute_account_balance(p_account_id UUID)\nRETURNS NUMERIC(78,0)\nLANGUAGE plpgsql AS $$\nDECLARE v_bal NUMERIC(78,0);\nBEGIN\n    PERFORM 1 FROM arka.accounts WHERE id = p_account_id FOR UPDATE;\n\n    SELECT COALESCE(SUM(\n             CASE WHEN acc.normal_balance = 'DEBIT'\n                  THEN jl.debit - jl.credit\n                  ELSE jl.credit - jl.debit END), 0)\n      INTO v_bal\n      FROM arka.journal_lines jl\n      JOIN arka.journal_entries je ON je.id = jl.entry_id\n      JOIN arka.accounts acc ON acc.id = jl.account_id\n     WHERE jl.account_id = p_account_id\n       AND je.status = 'POSTED'\n       AND je.deleted_at IS NULL;\n\n    UPDATE arka.accounts\n       SET balance = v_bal, balance_version = balance_version + 1\n     WHERE id = p_account_id;\n    RETURN v_bal;\nEND;$$;\n\n-- ---------------------------------------------------------------------------\n--  FISCAL CLOSE — advisory-locked so only one close can run system-wide.\n--  Rolls net income (Income - Expense) of the period into a Retained Earnings\n--  equity account and locks the period.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE FUNCTION arka.fn_close_fiscal_period(\n    p_period_id           UUID,\n    p_retained_account_id UUID,\n    p_pl_summary_acct_id  UUID,\n    p_actor               UUID DEFAULT NULL\n) RETURNS arka.journal_entries\nLANGUAGE plpgsql\nSECURITY DEFINER\nSET search_path = arka, public\nAS $$\nDECLARE\n    v_period   arka.fiscal_periods;\n    v_income   NUMERIC(78,0);\n    v_expense  NUMERIC(78,0);\n    v_net      NUMERIC(78,0);\n    v_entry_id UUID;\n    v_result   arka.journal_entries;\n    v_open     INTEGER;\nBEGIN\n    -- Only one fiscal-close may execute across the whole database at a time.\n    IF NOT pg_try_advisory_xact_lock(hashtext('arka.fiscal.close')) THEN\n        RAISE EXCEPTION 'another fiscal close is already in progress';\n    END IF;\n\n    SELECT * INTO v_period FROM arka.fiscal_periods WHERE id = p_period_id FOR UPDATE;\n    IF NOT FOUND THEN RAISE EXCEPTION 'period % not found', p_period_id; END IF;\n    IF v_period.status = 'CLOSED' THEN\n        RAISE EXCEPTION 'period %/% already CLOSED', v_period.year_code, v_period.period_no;\n    END IF;\n\n    -- Refuse to close while draft entries remain in the period window.\n    SELECT COUNT(*) INTO v_open\n      FROM arka.journal_entries\n     WHERE status = 'DRAFT' AND deleted_at IS NULL\n       AND entry_date BETWEEN v_period.starts_on AND v_period.ends_on;\n    IF v_open > 0 THEN\n        RAISE EXCEPTION 'cannot close: % draft entries still in period', v_open;\n    END IF;\n\n    -- Net income for the period from posted lines.\n    SELECT\n      COALESCE(SUM(CASE WHEN acc.account_type = 'INCOME'  THEN jl.credit - jl.debit ELSE 0 END),0),\n      COALESCE(SUM(CASE WHEN acc.account_type = 'EXPENSE' THEN jl.debit - jl.credit ELSE 0 END),0)\n      INTO v_income, v_expense\n      FROM arka.journal_lines jl\n      JOIN arka.journal_entries je ON je.id = jl.entry_id\n      JOIN arka.accounts acc ON acc.id = jl.account_id\n     WHERE je.status = 'POSTED' AND je.deleted_at IS NULL\n       AND je.entry_date BETWEEN v_period.starts_on AND v_period.ends_on;\n\n    v_net := v_income - v_expense;   -- positive = profit\n\n    -- Closing entry: move net result into Retained Earnings via a summary account.\n    INSERT INTO arka.journal_entries (memo, entry_date, source, status, created_by)\n    VALUES ('Fiscal close ' || v_period.year_code || '/' || v_period.period_no,\n            v_period.ends_on, 'CLOSING', 'DRAFT', COALESCE(p_actor, arka.current_actor_id()))\n    RETURNING id INTO v_entry_id;\n\n    IF v_net > 0 THEN\n        -- Profit: debit P&L summary, credit retained earnings.\n        INSERT INTO arka.journal_lines (entry_id, line_no, account_id, debit, credit, memo)\n        VALUES (v_entry_id, 1, p_pl_summary_acct_id, v_net, 0, 'Net profit to summary'),\n               (v_entry_id, 2, p_retained_account_id, 0, v_net, 'Net profit to retained earnings');\n    ELSIF v_net < 0 THEN\n        INSERT INTO arka.journal_lines (entry_id, line_no, account_id, debit, credit, memo)\n        VALUES (v_entry_id, 1, p_retained_account_id, -v_net, 0, 'Net loss from retained earnings'),\n               (v_entry_id, 2, p_pl_summary_acct_id, 0, -v_net, 'Net loss to summary');\n    ELSE\n        -- Zero net result: no closing entry is needed (a 0/0 line would violate\n        -- chk_line_one_side). Discard the empty header.\n        DELETE FROM arka.journal_entries WHERE id = v_entry_id;\n        v_entry_id := NULL;\n    END IF;\n\n    IF v_entry_id IS NOT NULL THEN\n        v_result := arka.fn_post_journal_entry(v_entry_id, p_actor);\n    END IF;\n\n    UPDATE arka.fiscal_periods\n       SET status = 'CLOSED', closed_at = now(),\n           closed_by = COALESCE(p_actor, arka.current_actor_id())\n     WHERE id = p_period_id;\n\n    RETURN v_result;\nEND;\n$$;\n\n-- Application pool executes the gates but cannot mutate cached balances directly.\n-- (Column-level restriction requires revoking the table-level UPDATE first, then\n--  re-granting UPDATE only on the non-balance columns.)\nREVOKE UPDATE ON arka.accounts FROM arka_app;\nGRANT UPDATE (name, is_active, description, metadata, parent_id, currency,\n              updated_at, deleted_at)\n    ON arka.accounts TO arka_app;\n\nGRANT EXECUTE ON FUNCTION\n    arka.fn_post_journal_entry(UUID, UUID),\n    arka.fn_reverse_journal_entry(UUID, UUID, DATE, TEXT),\n    arka.fn_recompute_account_balance(UUID),\n    arka.fn_close_fiscal_period(UUID, UUID, UUID, UUID)\nTO arka_app;\n" },
  { name: "06_reporting_views.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 06 — Reporting Views (WITH RECURSIVE)\n--  -------------------------------------------------------------------------\n--    v_account_tree       — hierarchical COA with depth + materialised path\n--    v_account_rollup     — balances rolled up from leaves to every ancestor\n--    v_trial_balance      — posted debits/credits per postable account\n--    v_general_ledger     — flattened posted lines (drill-down source)\n--    v_profit_and_loss    — income vs expense, net result\n--    v_balance_sheet      — assets = liabilities + equity assertion\n--    v_cash_flow_summary  — movement across cash/bank accounts\n--    v_ar_aging           — receivables aging buckets by customer\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---------------------------------------------------------------------------\n--  Hierarchical Chart of Accounts\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_account_tree AS\nWITH RECURSIVE tree AS (\n    SELECT\n        a.id, a.code, a.name, a.account_type, a.normal_balance,\n        a.parent_id, a.is_postable, a.is_active, a.balance,\n        1                          AS depth,\n        ARRAY[a.code]              AS path_codes,\n        a.code::text               AS path_display,\n        a.code                     AS root_code\n    FROM arka.accounts a\n    WHERE a.parent_id IS NULL AND a.deleted_at IS NULL\n\n    UNION ALL\n\n    SELECT\n        c.id, c.code, c.name, c.account_type, c.normal_balance,\n        c.parent_id, c.is_postable, c.is_active, c.balance,\n        t.depth + 1,\n        t.path_codes || c.code,\n        t.path_display || ' › ' || c.code,\n        t.root_code\n    FROM arka.accounts c\n    JOIN tree t ON c.parent_id = t.id\n    WHERE c.deleted_at IS NULL\n)\nSELECT * FROM tree;\n\n-- ---------------------------------------------------------------------------\n--  Roll-up: every account's balance including all descendants.\n--  Each node's cached balance is propagated to itself and each ancestor.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_account_rollup AS\nWITH RECURSIVE up AS (\n    SELECT a.id AS ancestor_id, a.id AS node_id, a.balance\n    FROM arka.accounts a\n    WHERE a.deleted_at IS NULL\n\n    UNION ALL\n\n    SELECT p.id AS ancestor_id, u.node_id, u.balance\n    FROM up u\n    JOIN arka.accounts c ON c.id = u.ancestor_id AND c.deleted_at IS NULL\n    JOIN arka.accounts p ON p.id = c.parent_id AND p.deleted_at IS NULL\n)\nSELECT\n    a.id, a.code, a.name, a.account_type, a.normal_balance, a.is_postable,\n    COALESCE(SUM(u.balance), 0)::numeric(78,0) AS rollup_balance\nFROM arka.accounts a\nLEFT JOIN up u ON u.ancestor_id = a.id\nWHERE a.deleted_at IS NULL\nGROUP BY a.id, a.code, a.name, a.account_type, a.normal_balance, a.is_postable;\n\n-- ---------------------------------------------------------------------------\n--  Trial Balance — from POSTED lines only.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_trial_balance AS\nSELECT\n    a.id                                        AS account_id,\n    a.code,\n    a.name,\n    a.account_type,\n    a.normal_balance,\n    COALESCE(SUM(jl.debit), 0)::numeric(78,0)   AS total_debit,\n    COALESCE(SUM(jl.credit), 0)::numeric(78,0)  AS total_credit,\n    -- Natural balance in the account's normal direction:\n    CASE WHEN a.normal_balance = 'DEBIT'\n         THEN COALESCE(SUM(jl.debit - jl.credit), 0)\n         ELSE COALESCE(SUM(jl.credit - jl.debit), 0)\n    END::numeric(78,0)                          AS net_balance,\n    -- Presentation columns (a TB always balances across all accounts):\n    GREATEST(COALESCE(SUM(jl.debit - jl.credit), 0), 0)::numeric(78,0)  AS debit_balance,\n    GREATEST(COALESCE(SUM(jl.credit - jl.debit), 0), 0)::numeric(78,0)  AS credit_balance\nFROM arka.accounts a\nLEFT JOIN arka.journal_lines jl ON jl.account_id = a.id\nLEFT JOIN arka.journal_entries je\n       ON je.id = jl.entry_id AND je.status = 'POSTED' AND je.deleted_at IS NULL\nWHERE a.deleted_at IS NULL AND a.is_postable\nGROUP BY a.id, a.code, a.name, a.account_type, a.normal_balance\nORDER BY a.code;\n\n-- ---------------------------------------------------------------------------\n--  General Ledger — flattened posted lines for drill-down / statements.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_general_ledger AS\nSELECT\n    je.entry_no,\n    je.entry_date,\n    je.status,\n    je.memo             AS entry_memo,\n    je.reference,\n    je.source,\n    a.code              AS account_code,\n    a.name              AS account_name,\n    a.account_type,\n    jl.line_no,\n    jl.debit,\n    jl.credit,\n    jl.memo             AS line_memo,\n    p.code              AS project_code,\n    p.name              AS project_name,\n    je.id               AS entry_id,\n    jl.id               AS line_id,\n    a.id                AS account_id,\n    je.posted_at\nFROM arka.journal_lines jl\nJOIN arka.journal_entries je ON je.id = jl.entry_id\nJOIN arka.accounts a        ON a.id = jl.account_id\nLEFT JOIN arka.projects p   ON p.id = jl.project_id\nWHERE je.status = 'POSTED' AND je.deleted_at IS NULL;\n\n-- ---------------------------------------------------------------------------\n--  Profit & Loss  (income & expense roll-ups). Filter by date in the app.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_profit_and_loss AS\nSELECT\n    a.account_type,\n    a.code,\n    a.name,\n    CASE WHEN a.account_type = 'INCOME'\n         THEN COALESCE(SUM(jl.credit - jl.debit), 0)\n         ELSE COALESCE(SUM(jl.debit  - jl.credit), 0)\n    END::numeric(78,0)  AS amount,\n    je.entry_date\nFROM arka.accounts a\nJOIN arka.journal_lines jl   ON jl.account_id = a.id\nJOIN arka.journal_entries je ON je.id = jl.entry_id\n                            AND je.status = 'POSTED' AND je.deleted_at IS NULL\nWHERE a.account_type IN ('INCOME','EXPENSE') AND a.deleted_at IS NULL\nGROUP BY a.account_type, a.code, a.name, je.entry_date;\n\n-- ---------------------------------------------------------------------------\n--  Balance Sheet snapshot (all posted activity to date).\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_balance_sheet AS\nSELECT\n    a.account_type,\n    a.code,\n    a.name,\n    r.rollup_balance    AS amount\nFROM arka.accounts a\nJOIN arka.v_account_rollup r ON r.id = a.id\nWHERE a.account_type IN ('ASSET','LIABILITY','EQUITY')\n  AND a.deleted_at IS NULL\n  AND a.parent_id IS NULL;   -- top-level summary rows\n\n-- ---------------------------------------------------------------------------\n--  Cash Flow summary — net movement over accounts flagged as cash/bank\n--  (identified by metadata->>'cash_flow' = 'true' in the COA seed).\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_cash_flow_summary AS\nSELECT\n    je.entry_date,\n    a.code,\n    a.name,\n    COALESCE(SUM(jl.debit - jl.credit), 0)::numeric(78,0) AS net_inflow\nFROM arka.accounts a\nJOIN arka.journal_lines jl   ON jl.account_id = a.id\nJOIN arka.journal_entries je ON je.id = jl.entry_id\n                            AND je.status = 'POSTED' AND je.deleted_at IS NULL\nWHERE a.metadata->>'cash_flow' = 'true' AND a.deleted_at IS NULL\nGROUP BY je.entry_date, a.code, a.name;\n\n-- ---------------------------------------------------------------------------\n--  Accounts-Receivable aging by customer (open, per project invoicing).\n--  Buckets are computed against the customer AR account balance snapshots.\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_ar_aging AS\nSELECT\n    c.id                                        AS customer_id,\n    c.code                                      AS customer_code,\n    c.display_name,\n    a.balance                                   AS receivable_balance,\n    c.credit_limit,\n    GREATEST(c.credit_limit - a.balance, 0)::numeric(78,0) AS available_credit\nFROM arka.customers c\nJOIN arka.accounts a ON a.id = c.ar_account_id\nWHERE c.deleted_at IS NULL;\n\n-- Read-only reporting surface for the app pool.\nGRANT SELECT ON\n    arka.v_account_tree, arka.v_account_rollup, arka.v_trial_balance,\n    arka.v_general_ledger, arka.v_profit_and_loss, arka.v_balance_sheet,\n    arka.v_cash_flow_summary, arka.v_ar_aging\nTO arka_app;\n" },
  { name: "07_rbac_seed.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 07 — RBAC Catalogue, Role Grants, Segregation of Duties\n--  -------------------------------------------------------------------------\n--  Maker/checker model. Grants are deliberately arranged so NO single role\n--  ever holds a conflicting pair — the fn_enforce_sod trigger would reject it.\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---------------------------------------------------------------------------\n--  1) Permission catalogue\n-- ---------------------------------------------------------------------------\nINSERT INTO arka.permissions (code, description, category) VALUES\n  ('ledger.view',      'View journal entries and ledgers',            'ledger'),\n  ('ledger.create',    'Draft journal entries',                       'ledger'),\n  ('ledger.post',      'Post (finalise) journal entries',             'ledger'),\n  ('ledger.reverse',   'Reverse posted journal entries',              'ledger'),\n  ('fund.transfer',    'Execute bank/cashbox fund transfers',         'treasury'),\n  ('invoice.issue',    'Issue customer invoices',                     'sales'),\n  ('invoice.approve',  'Approve issued invoices',                     'sales'),\n  ('report.financial', 'Access financial statements',                 'reporting'),\n  ('report.ceo',       'Access CEO dashboard & board reports',        'reporting'),\n  ('project.view',     'View projects',                               'projects'),\n  ('project.manage',   'Create/update/close projects & tasks',        'projects'),\n  ('customer.view',    'View customers',                              'crm'),\n  ('customer.manage',  'Create/update customers',                     'crm'),\n  ('hr.view',          'View personnel records',                      'hr'),\n  ('hr.manage',        'Manage personnel lifecycle',                  'hr'),\n  ('payroll.run',      'Execute payroll runs',                        'hr'),\n  ('asset.view',       'View assets/inventory',                       'assets'),\n  ('asset.manage',     'Check-in/out, maintenance, depreciation',     'assets'),\n  ('user.manage',      'Create/disable user accounts',                'admin'),\n  ('role.manage',      'Assign roles & permissions',                  'admin'),\n  ('audit.view',       'Read the audit trail',                        'admin'),\n  ('ai.query',         'Use AI analytics / chat-with-database',       'analytics'),\n  ('system.admin',     'System configuration & monitoring',           'admin')\nON CONFLICT (code) DO NOTHING;\n\n-- ---------------------------------------------------------------------------\n--  2) Segregation-of-Duties conflicts (permission_a < permission_b enforced)\n-- ---------------------------------------------------------------------------\nINSERT INTO arka.sod_conflicts (permission_a, permission_b, reason) VALUES\n  ('fund.transfer',   'ledger.reverse', 'A person who moves funds must not also reverse the ledger record of it'),\n  ('invoice.approve', 'invoice.issue',  'Invoice issuer must differ from invoice approver (maker/checker)'),\n  ('ledger.post',     'user.manage',    'Ledger poster must not administer users/roles (privilege escalation)'),\n  ('payroll.run',     'user.manage',    'Payroll operator must not administer user accounts')\nON CONFLICT DO NOTHING;\n\n-- ---------------------------------------------------------------------------\n--  3) Role grants (validated against SoD on insert)\n-- ---------------------------------------------------------------------------\n\n-- CEO — oversight, correction authority, administration. Executes NO postings\n-- or transfers (that is the accountant's execution duty).\nINSERT INTO arka.role_permissions (role, permission) VALUES\n  ('CEO','ledger.view'), ('CEO','ledger.reverse'), ('CEO','invoice.approve'),\n  ('CEO','report.financial'), ('CEO','report.ceo'),\n  ('CEO','project.view'), ('CEO','project.manage'),\n  ('CEO','customer.view'), ('CEO','customer.manage'), ('CEO','hr.view'), ('CEO','hr.manage'),\n  ('CEO','asset.view'), ('CEO','user.manage'), ('CEO','role.manage'),\n  ('CEO','audit.view'), ('CEO','ai.query'), ('CEO','system.admin')\nON CONFLICT DO NOTHING;\n\n-- ACCOUNTANT — financial execution: drafts, posts, transfers, invoices, payroll.\nINSERT INTO arka.role_permissions (role, permission) VALUES\n  ('ACCOUNTANT','ledger.view'), ('ACCOUNTANT','ledger.create'),\n  ('ACCOUNTANT','ledger.post'), ('ACCOUNTANT','fund.transfer'),\n  ('ACCOUNTANT','invoice.issue'), ('ACCOUNTANT','report.financial'),\n  ('ACCOUNTANT','customer.view'), ('ACCOUNTANT','project.view'),\n  ('ACCOUNTANT','asset.view'), ('ACCOUNTANT','hr.view'),\n  ('ACCOUNTANT','payroll.run')\nON CONFLICT DO NOTHING;\n\n-- SALES — CRM & invoice origination.\nINSERT INTO arka.role_permissions (role, permission) VALUES\n  ('SALES','customer.view'), ('SALES','customer.manage'),\n  ('SALES','project.view'), ('SALES','invoice.issue'), ('SALES','ai.query')\nON CONFLICT DO NOTHING;\n\n-- DESIGNER / DEVELOPER — delivery contributors.\nINSERT INTO arka.role_permissions (role, permission) VALUES\n  ('DESIGNER','project.view'),  ('DESIGNER','asset.view'),\n  ('DEVELOPER','project.view'), ('DEVELOPER','asset.view')\nON CONFLICT DO NOTHING;\n\n-- PHOTOGRAPHER — delivery + gear custody.\nINSERT INTO arka.role_permissions (role, permission) VALUES\n  ('PHOTOGRAPHER','project.view'), ('PHOTOGRAPHER','asset.view'),\n  ('PHOTOGRAPHER','asset.manage')\nON CONFLICT DO NOTHING;\n\n-- CUSTOMER — self-service (row scope enforced in the app layer).\nINSERT INTO arka.role_permissions (role, permission) VALUES\n  ('CUSTOMER','project.view')\nON CONFLICT DO NOTHING;\n\n-- GUEST — no grants (authentication landing only).\n\n-- ---------------------------------------------------------------------------\n--  Convenience: effective permissions per user\n-- ---------------------------------------------------------------------------\nCREATE OR REPLACE VIEW arka.v_user_permissions AS\nSELECT u.id AS user_id, u.email, u.role, rp.permission\nFROM arka.users u\nJOIN arka.role_permissions rp ON rp.role = u.role\nWHERE u.deleted_at IS NULL;\n\nGRANT SELECT ON arka.v_user_permissions TO arka_app;\n" },
  { name: "08_seed_data.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 08 — Bootstrap Seed Data\n--  -------------------------------------------------------------------------\n--  * Full Chart of Accounts (creative-agency, IRR, amounts in Rial).\n--  * Jalali fiscal periods for year 1405.\n--  * Sample customers, projects, and a set of *posted* journal entries so the\n--    trial balance, P&L and dashboards render real numbers on first launch.\n--  NOTE: The CEO login user is provisioned by the backend bootstrap (argon2id\n--        hashing happens in the app layer), see backend/src/bootstrap.\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---------------------------------------------------------------------------\n--  CHART OF ACCOUNTS — roots first, then sub-headers, then postable leaves.\n--  (trg_accounts_parent_leaf auto-marks any account that gains a child as\n--   non-postable, so parents need not be flagged manually.)\n-- ---------------------------------------------------------------------------\nINSERT INTO arka.accounts (code, name, account_type, normal_balance, parent_id) VALUES\n  ('1', 'دارایی‌ها',                 'ASSET',     'DEBIT',  NULL),\n  ('2', 'بدهی‌ها',                   'LIABILITY', 'CREDIT', NULL),\n  ('3', 'حقوق صاحبان سرمایه',        'EQUITY',    'CREDIT', NULL),\n  ('4', 'درآمدها',                   'INCOME',    'CREDIT', NULL),\n  ('5', 'هزینه‌ها',                  'EXPENSE',   'DEBIT',  NULL);\n\n-- Sub-headers\nINSERT INTO arka.accounts (code, name, account_type, normal_balance, parent_id)\nSELECT v.code, v.name, v.atype::arka.account_type, v.nb::arka.normal_balance,\n       (SELECT id FROM arka.accounts WHERE code = v.parent)\nFROM (VALUES\n  ('10',   'دارایی‌های جاری',        'ASSET',     'DEBIT',  '1'),\n  ('15',   'دارایی‌های ثابت',        'ASSET',     'DEBIT',  '1'),\n  ('20',   'بدهی‌های جاری',          'LIABILITY', 'CREDIT', '2'),\n  ('25',   'بدهی‌های بلندمدت',       'LIABILITY', 'CREDIT', '2'),\n  ('50',   'هزینه‌های عملیاتی',      'EXPENSE',   'DEBIT',  '5')\n) AS v(code, name, atype, nb, parent);\n\n-- AR control (parent of per-customer sub-ledgers) under Current Assets\nINSERT INTO arka.accounts (code, name, account_type, normal_balance, parent_id)\nSELECT '1100', 'حساب‌های دریافتنی (کنترل)', 'ASSET', 'DEBIT',\n       (SELECT id FROM arka.accounts WHERE code = '10');\n\n-- Postable leaves\nINSERT INTO arka.accounts (code, name, account_type, normal_balance, parent_id, metadata)\nSELECT v.code, v.name, v.atype::arka.account_type, v.nb::arka.normal_balance,\n       (SELECT id FROM arka.accounts WHERE code = v.parent),\n       v.meta::jsonb\nFROM (VALUES\n  -- Current assets\n  ('1010', 'صندوق',                        'ASSET','DEBIT','10','{\"cash_flow\":\"true\"}'),\n  ('1020', 'بانک ملت - حساب اصلی',         'ASSET','DEBIT','10','{\"cash_flow\":\"true\"}'),\n  ('1030', 'بانک - حساب عملیاتی',          'ASSET','DEBIT','10','{\"cash_flow\":\"true\"}'),\n  ('1200', 'پیش‌پرداخت‌ها',                'ASSET','DEBIT','10','{}'),\n  ('1300', 'مالیات ارزش افزوده دریافتنی',  'ASSET','DEBIT','10','{}'),\n  -- Fixed assets\n  ('1500', 'تجهیزات عکاسی',                'ASSET','DEBIT','15','{}'),\n  ('1510', 'رایانه و تجهیزات مک',          'ASSET','DEBIT','15','{}'),\n  ('1520', 'تجهیزات نور و صدا',            'ASSET','DEBIT','15','{}'),\n  ('1590', 'استهلاک انباشته',              'ASSET','CREDIT','15','{}'),   -- contra-asset\n  -- Current liabilities\n  ('2010', 'حساب‌های پرداختنی',            'LIABILITY','CREDIT','20','{}'),\n  ('2020', 'حقوق پرداختنی',                'LIABILITY','CREDIT','20','{}'),\n  ('2030', 'مالیات ارزش افزوده پرداختنی',  'LIABILITY','CREDIT','20','{}'),\n  ('2040', 'بیمه پرداختنی',                'LIABILITY','CREDIT','20','{}'),\n  ('2050', 'مالیات پرداختنی',              'LIABILITY','CREDIT','20','{}'),\n  -- Long-term liabilities\n  ('2500', 'تسهیلات و وام‌ها',             'LIABILITY','CREDIT','25','{}'),\n  -- Operating expenses\n  ('5010', 'حقوق و دستمزد',                'EXPENSE','DEBIT','50','{}'),\n  ('5020', 'اجاره',                        'EXPENSE','DEBIT','50','{}'),\n  ('5030', 'آب، برق و انرژی',              'EXPENSE','DEBIT','50','{}'),\n  ('5040', 'اشتراک نرم‌افزار',             'EXPENSE','DEBIT','50','{}'),\n  ('5050', 'اجاره تجهیزات',                'EXPENSE','DEBIT','50','{}'),\n  ('5060', 'بازاریابی و تبلیغات',          'EXPENSE','DEBIT','50','{}'),\n  ('5070', 'هزینه استهلاک',                'EXPENSE','DEBIT','50','{}'),\n  ('5080', 'هزینه بیمه',                   'EXPENSE','DEBIT','50','{}'),\n  ('5090', 'کارمزد بانکی',                 'EXPENSE','DEBIT','50','{}'),\n  ('5100', 'هزینه پیمانکار/فریلنسر',       'EXPENSE','DEBIT','50','{}'),\n  ('5900', 'هزینه‌های متفرقه',             'EXPENSE','DEBIT','50','{}')\n) AS v(code, name, atype, nb, parent, meta);\n\n-- Equity leaves (directly under root 3)\nINSERT INTO arka.accounts (code, name, account_type, normal_balance, parent_id)\nSELECT v.code, v.name, 'EQUITY'::arka.account_type, v.nb::arka.normal_balance,\n       (SELECT id FROM arka.accounts WHERE code = '3')\nFROM (VALUES\n  ('3010', 'سرمایه - علی جعفری',  'CREDIT'),\n  ('3020', 'برداشت مالک',          'DEBIT'),    -- contra-equity\n  ('3030', 'سود انباشته',          'CREDIT'),\n  ('3040', 'خلاصه سود و زیان',     'CREDIT')\n) AS v(code, name, nb);\n\n-- Income leaves (directly under root 4)\nINSERT INTO arka.accounts (code, name, account_type, normal_balance, parent_id)\nSELECT v.code, v.name, 'INCOME'::arka.account_type, 'CREDIT'::arka.normal_balance,\n       (SELECT id FROM arka.accounts WHERE code = '4')\nFROM (VALUES\n  ('4010', 'خدمات عکاسی'),\n  ('4020', 'خدمات طراحی UI/UX'),\n  ('4030', 'خدمات موشن‌گرافیک'),\n  ('4040', 'تولید تبلیغات'),\n  ('4090', 'سایر درآمدها')\n) AS v(code, name);\n\n-- ---------------------------------------------------------------------------\n--  FISCAL PERIODS — Jalali year 1405 (Gregorian boundaries).\n-- ---------------------------------------------------------------------------\nINSERT INTO arka.fiscal_periods (year_code, period_no, starts_on, ends_on) VALUES\n  ('1405', 1,  DATE '2026-03-21', DATE '2026-04-20'),\n  ('1405', 2,  DATE '2026-04-21', DATE '2026-05-21'),\n  ('1405', 3,  DATE '2026-05-22', DATE '2026-06-21'),\n  ('1405', 4,  DATE '2026-06-22', DATE '2026-07-22'),\n  ('1405', 5,  DATE '2026-07-23', DATE '2026-08-22'),\n  ('1405', 6,  DATE '2026-08-23', DATE '2026-09-22'),\n  ('1405', 7,  DATE '2026-09-23', DATE '2026-10-22'),\n  ('1405', 8,  DATE '2026-10-23', DATE '2026-11-21'),\n  ('1405', 9,  DATE '2026-11-22', DATE '2026-12-21'),\n  ('1405', 10, DATE '2026-12-22', DATE '2027-01-20'),\n  ('1405', 11, DATE '2027-01-21', DATE '2027-02-19'),\n  ('1405', 12, DATE '2027-02-20', DATE '2027-03-20');\n\n-- ---------------------------------------------------------------------------\n--  No sample customers / projects / journal entries are seeded.\n--  The system starts clean; all business data is entered by the user.\n--  (Chart of accounts, fiscal periods and the CEO/accountant logins remain.)\n-- ---------------------------------------------------------------------------\n\nANALYZE;\n" },
  { name: "09_soft_delete_and_permissions.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 09 — Soft-delete metadata, per-user permissions, code seqs\n--  -------------------------------------------------------------------------\n--  Idempotent (IF NOT EXISTS) so it is safe both on a fresh init and when\n--  applied to an already-running database.\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---- Soft-delete audit metadata (who deleted + mandatory reason) ------------\nALTER TABLE arka.journal_entries ADD COLUMN IF NOT EXISTS deleted_by     UUID REFERENCES arka.users(id);\nALTER TABLE arka.journal_entries ADD COLUMN IF NOT EXISTS deleted_reason TEXT;\n\nALTER TABLE arka.projects         ADD COLUMN IF NOT EXISTS deleted_by     UUID REFERENCES arka.users(id);\nALTER TABLE arka.projects         ADD COLUMN IF NOT EXISTS deleted_reason TEXT;\n\nALTER TABLE arka.customers        ADD COLUMN IF NOT EXISTS deleted_by     UUID REFERENCES arka.users(id);\nALTER TABLE arka.customers        ADD COLUMN IF NOT EXISTS deleted_reason TEXT;\n\n-- ---- Per-user explicit permission grants ------------------------------------\n-- When a user has ANY rows here, those replace the role defaults (full control\n-- from the \"create user\" checkboxes). Empty ⇒ fall back to role_permissions.\nCREATE TABLE IF NOT EXISTS arka.user_permissions (\n    user_id    UUID NOT NULL REFERENCES arka.users(id) ON DELETE CASCADE,\n    permission TEXT NOT NULL REFERENCES arka.permissions(code) ON DELETE CASCADE,\n    granted_at TIMESTAMPTZ NOT NULL DEFAULT now(),\n    PRIMARY KEY (user_id, permission)\n);\nCREATE INDEX IF NOT EXISTS idx_user_permissions_user ON arka.user_permissions (user_id);\n\n-- ---- Sequences for auto-generated human codes -------------------------------\nCREATE SEQUENCE IF NOT EXISTS arka.seq_project_code  START 3001;\nCREATE SEQUENCE IF NOT EXISTS arka.seq_customer_code START 2001;\n\n-- ---- Effective permissions view (custom overrides role) ---------------------\nCREATE OR REPLACE VIEW arka.v_effective_permissions AS\nSELECT u.id AS user_id,\n       COALESCE(up.permission, rp.permission) AS permission\nFROM arka.users u\nLEFT JOIN arka.user_permissions up ON up.user_id = u.id\nLEFT JOIN arka.role_permissions rp ON rp.role = u.role\n     AND NOT EXISTS (SELECT 1 FROM arka.user_permissions x WHERE x.user_id = u.id)\nWHERE u.deleted_at IS NULL\n  AND COALESCE(up.permission, rp.permission) IS NOT NULL;\n\nGRANT SELECT ON arka.v_effective_permissions TO arka_app;\nGRANT SELECT, INSERT, UPDATE, DELETE ON arka.user_permissions TO arka_app;\nGRANT USAGE, SELECT ON SEQUENCE arka.seq_project_code, arka.seq_customer_code TO arka_app;\n" },
  { name: "10_hr_tasks_payroll.sql", sql: "-- =============================================================================\n--  ARKA ADS STUDIO — 10 — Human Resources, Team Workspace (Tasks), Payroll\n--  -------------------------------------------------------------------------\n--  Idempotent. Adds: positions, personnel, tasks (personal/group),\n--  payroll_runs + payslips, code sequences, and the task.manage permission.\n-- =============================================================================\nSET search_path TO arka, public;\n\n-- ---- Job positions ----------------------------------------------------------\nCREATE TABLE IF NOT EXISTS arka.positions (\n    id          UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    title       TEXT NOT NULL,\n    description TEXT,\n    created_at  TIMESTAMPTZ NOT NULL DEFAULT now()\n);\nCREATE UNIQUE INDEX IF NOT EXISTS uq_positions_title ON arka.positions (lower(title));\n\n-- ---- Personnel (HR master) --------------------------------------------------\nCREATE SEQUENCE IF NOT EXISTS arka.seq_employee_code START 1001;\n\nCREATE TABLE IF NOT EXISTS arka.personnel (\n    id                UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    employee_code     TEXT NOT NULL,\n    user_id           UUID REFERENCES arka.users(id),      -- optional login link\n    first_name        TEXT NOT NULL,\n    last_name         TEXT NOT NULL,\n    national_id_enc   BYTEA,                               -- envelope-encrypted\n    national_id_last4 TEXT,\n    birth_date        DATE,\n    gender            TEXT,\n    phone             TEXT,\n    email             TEXT,\n    address           TEXT,\n    position_id       UUID REFERENCES arka.positions(id),\n    department        TEXT,\n    hire_date         DATE,\n    base_salary       NUMERIC(78,0) NOT NULL DEFAULT 0 CHECK (base_salary >= 0),\n    iban_enc          BYTEA,\n    iban_last4        TEXT,\n    employment_status TEXT NOT NULL DEFAULT 'ACTIVE',      -- ACTIVE|ON_LEAVE|TERMINATED\n    emergency_contact TEXT,\n    metadata          JSONB NOT NULL DEFAULT '{}'::jsonb,\n    created_by        UUID REFERENCES arka.users(id),\n    created_at        TIMESTAMPTZ NOT NULL DEFAULT now(),\n    updated_at        TIMESTAMPTZ NOT NULL DEFAULT now(),\n    deleted_at        TIMESTAMPTZ,\n    deleted_by        UUID REFERENCES arka.users(id),\n    deleted_reason    TEXT,\n    CONSTRAINT chk_emp_status CHECK (employment_status IN ('ACTIVE','ON_LEAVE','TERMINATED'))\n);\nCREATE UNIQUE INDEX IF NOT EXISTS uq_personnel_code ON arka.personnel (employee_code) WHERE deleted_at IS NULL;\nCREATE UNIQUE INDEX IF NOT EXISTS uq_personnel_user ON arka.personnel (user_id) WHERE user_id IS NOT NULL AND deleted_at IS NULL;\nCREATE INDEX IF NOT EXISTS idx_personnel_position ON arka.personnel (position_id);\n\nDROP TRIGGER IF EXISTS trg_personnel_touch ON arka.personnel;\nCREATE TRIGGER trg_personnel_touch BEFORE UPDATE ON arka.personnel\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_touch_updated_at();\nDROP TRIGGER IF EXISTS trg_personnel_audit ON arka.personnel;\nCREATE TRIGGER trg_personnel_audit AFTER INSERT OR UPDATE OR DELETE ON arka.personnel\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_audit();\n\n-- ---- Tasks (team workspace: personal + group) -------------------------------\nCREATE SEQUENCE IF NOT EXISTS arka.seq_task_code START 1;\n\nCREATE TABLE IF NOT EXISTS arka.tasks (\n    id             UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    task_code      TEXT NOT NULL,\n    title          TEXT NOT NULL,\n    description    TEXT,\n    kind           TEXT NOT NULL DEFAULT 'PERSONAL',       -- PERSONAL | GROUP\n    assignee_id    UUID REFERENCES arka.users(id),         -- NULL when GROUP\n    project_id     UUID REFERENCES arka.projects(id),\n    status         TEXT NOT NULL DEFAULT 'TODO',           -- TODO|IN_PROGRESS|DONE|BLOCKED\n    priority       TEXT NOT NULL DEFAULT 'NORMAL',         -- LOW|NORMAL|HIGH|URGENT\n    due_date       DATE,\n    progress_pct   NUMERIC(5,2) NOT NULL DEFAULT 0 CHECK (progress_pct BETWEEN 0 AND 100),\n    created_by     UUID REFERENCES arka.users(id),\n    completed_at   TIMESTAMPTZ,\n    metadata       JSONB NOT NULL DEFAULT '{}'::jsonb,\n    created_at     TIMESTAMPTZ NOT NULL DEFAULT now(),\n    updated_at     TIMESTAMPTZ NOT NULL DEFAULT now(),\n    deleted_at     TIMESTAMPTZ,\n    deleted_by     UUID REFERENCES arka.users(id),\n    deleted_reason TEXT,\n    CONSTRAINT chk_task_kind     CHECK (kind IN ('PERSONAL','GROUP')),\n    CONSTRAINT chk_task_status   CHECK (status IN ('TODO','IN_PROGRESS','DONE','BLOCKED')),\n    CONSTRAINT chk_task_priority CHECK (priority IN ('LOW','NORMAL','HIGH','URGENT'))\n);\nCREATE INDEX IF NOT EXISTS idx_tasks_assignee ON arka.tasks (assignee_id) WHERE deleted_at IS NULL;\nCREATE INDEX IF NOT EXISTS idx_tasks_kind     ON arka.tasks (kind) WHERE deleted_at IS NULL;\nCREATE INDEX IF NOT EXISTS idx_tasks_project  ON arka.tasks (project_id);\n\nDROP TRIGGER IF EXISTS trg_tasks_touch ON arka.tasks;\nCREATE TRIGGER trg_tasks_touch BEFORE UPDATE ON arka.tasks\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_touch_updated_at();\nDROP TRIGGER IF EXISTS trg_tasks_audit ON arka.tasks;\nCREATE TRIGGER trg_tasks_audit AFTER INSERT OR UPDATE OR DELETE ON arka.tasks\n    FOR EACH ROW EXECUTE FUNCTION arka.fn_audit();\n\n-- ---- Payroll ----------------------------------------------------------------\nCREATE TABLE IF NOT EXISTS arka.payroll_runs (\n    id               UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    period_code      TEXT NOT NULL,                        -- e.g. 1405-04\n    run_date         DATE NOT NULL DEFAULT current_date,\n    status           TEXT NOT NULL DEFAULT 'DRAFT',        -- DRAFT|POSTED\n    total_net        NUMERIC(78,0) NOT NULL DEFAULT 0,\n    journal_entry_id UUID REFERENCES arka.journal_entries(id),\n    notes            TEXT,\n    created_by       UUID REFERENCES arka.users(id),\n    created_at       TIMESTAMPTZ NOT NULL DEFAULT now(),\n    CONSTRAINT chk_payroll_status CHECK (status IN ('DRAFT','POSTED'))\n);\nCREATE UNIQUE INDEX IF NOT EXISTS uq_payroll_period ON arka.payroll_runs (period_code);\n\nCREATE TABLE IF NOT EXISTS arka.payslips (\n    id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),\n    run_id       UUID NOT NULL REFERENCES arka.payroll_runs(id) ON DELETE CASCADE,\n    personnel_id UUID NOT NULL REFERENCES arka.personnel(id),\n    base_salary  NUMERIC(78,0) NOT NULL DEFAULT 0,\n    additions    NUMERIC(78,0) NOT NULL DEFAULT 0,\n    deductions   NUMERIC(78,0) NOT NULL DEFAULT 0,\n    tax          NUMERIC(78,0) NOT NULL DEFAULT 0,\n    insurance    NUMERIC(78,0) NOT NULL DEFAULT 0,\n    net          NUMERIC(78,0) NOT NULL DEFAULT 0,\n    detail       JSONB NOT NULL DEFAULT '{}'::jsonb,\n    created_at   TIMESTAMPTZ NOT NULL DEFAULT now()\n);\nCREATE INDEX IF NOT EXISTS idx_payslips_run ON arka.payslips (run_id);\nCREATE INDEX IF NOT EXISTS idx_payslips_personnel ON arka.payslips (personnel_id);\n\n-- ---- Permissions ------------------------------------------------------------\nINSERT INTO arka.permissions (code, description, category) VALUES\n  ('task.manage', 'Create and assign team tasks', 'workspace')\nON CONFLICT (code) DO NOTHING;\n\n-- CEO manages tasks. Payroll (payroll.run) stays with ACCOUNTANT by SoD design\n-- (it conflicts with user.manage which the CEO holds). The owner can still\n-- self-grant payroll.run to any account via the per-user permission checkboxes.\nINSERT INTO arka.role_permissions (role, permission) VALUES\n  ('CEO','task.manage')\nON CONFLICT DO NOTHING;\n\n-- ---- Convenience view: personnel with position + linked user ---------------\nCREATE OR REPLACE VIEW arka.v_personnel AS\nSELECT p.id, p.employee_code, p.user_id, p.first_name, p.last_name,\n       (p.first_name || ' ' || p.last_name) AS full_name,\n       p.national_id_last4, p.birth_date, p.gender, p.phone, p.email, p.address,\n       p.position_id, pos.title AS position_title, p.department, p.hire_date,\n       p.base_salary, p.iban_last4, p.employment_status, p.emergency_contact,\n       u.email AS login_email, p.created_at, p.deleted_at, p.deleted_reason,\n       p.deleted_by\nFROM arka.personnel p\nLEFT JOIN arka.positions pos ON pos.id = p.position_id\nLEFT JOIN arka.users u ON u.id = p.user_id;\n\n-- ---- Grants -----------------------------------------------------------------\nGRANT SELECT, INSERT, UPDATE, DELETE ON\n  arka.positions, arka.personnel, arka.tasks, arka.payroll_runs, arka.payslips TO arka_app;\nGRANT SELECT ON arka.v_personnel TO arka_app;\nGRANT USAGE, SELECT ON SEQUENCE arka.seq_employee_code, arka.seq_task_code TO arka_app;\n" },
];
